ALGORITHM CreateTransaction
INPUT: senderAddress, recipientAddress, amount
OUTPUT: transaction

BEGIN
 // Get sender's unspent outputs
 senderUTXOs = GetUnspentOutputs(senderAddress)

 // Calculate total amount of sender's UTXOs
 totalAmount = CalculateTotalAmount(senderUTXOs)

 // Check if sender has sufficient funds
 IF totalAmount < amount THEN
 THROW InsufficientFundsError
 END IF

 // Create transaction inputs
 inputs = CreateTransactionInputs(senderUTXOs, amount)

 // Create transaction outputs
 outputs = CreateTransactionOutputs(recipientAddress, amount)

 // Create transaction
 transaction = CreateTransaction(inputs, outputs)

 // Sign transaction with sender's private key
 SignTransaction(transaction, senderPrivateKey)

 RETURN transaction
END

